SELECT item_description, item_charge_amount
FROM claims_details
WHERE unit_price > 5.0;

SELECT COUNT(claim_id) AS total_claims_processed
FROM processing_logs
WHERE processed_by = 1;

SELECT action
FROM processing_logs
WHERE claim_id = 1;

SELECT COUNT(*) AS approved_claim_count
FROM claim_status
WHERE status = 'approved';

SELECT claim_id
FROM claim_status
WHERE status = 'submitted' AND next_status_date > CURRENT_DATE;

SELECT claim_id, SUM(item_charge_amount) AS total_charge, SUM(provider_payment_amount) AS total_payment
FROM claims_details
GROUP BY claim_id;
